var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"아카데미 클래스 관찰기록부 #001     \\n교육생 성명: <color=#ffd34c>한소림</color>     ","JPN":"アカデミークラス観察記録 #001     \\n教育生徒名：<color=#ffd34c>ハネダ・ミズキ</color>     ","ENG":"Academy Class Observation Record #001     \\nStudent Name: <color=#ffd34c>Han Sorim</color>     ","TWN":"學院觀察記錄簿 #001     \\n學生 姓名: <color=#ffd34c>琳</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"TEACHER_EXTRA_F_NULL","text":{"KOREA":"자, 오늘은 새로운 입학생이 왔어요.","JPN":"今日は、新入生が来てくれています。","ENG":"Alright, we have a new student today.","TWN":"那麼，今天我們來了一位新同學。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"TEACHER_EXTRA_F_NULL","text":{"KOREA":"소림 양? 우리, 자기소개를 해 볼까요?","JPN":"さあ、ハネダさん。自己紹介をどうぞ。","ENG":"Sorim? Will you introduce yourself?","TWN":"韓蕭林同學？做一下自我介紹吧。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"흠. 흠. 반갑다, 아카데미 동기생 여러분.","JPN":"う、うむ。お初にお目にかかる。アカデミーの同期諸君。","ENG":"Ahem. Ahem. It's nice to meet you, fellow Academy students.","TWN":"哼嗯，哼嗯。很高興見到你們，學院的各位同學們。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"본관은 애니멀 래스큐 스페셜포스 팀.","JPN":"本官はアニマル・レスキュースペシャルフォース、","ENG":"I come from the Animal Rescue Special Force Team,","TWN":"本官在動物救助特種部隊……"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"통칭 A.R.S 화이트 래빗에서 사격술고문으로 활동 중인 베테랑 솔저, 한소림 병장이다.","JPN":"通称A.R.Sホワイトラビットに射撃術顧問として務めている\\nベテランソルジャー、ハネダ・ミズキ兵長である。","ENG":"a.k.a. A.R.S. White Rabbit. I am Sergeant Han Sorim, a veteran soldier and also the marksmanship adviser.","TWN":"通稱A.R.S白兔社中，擔當射擊技術顧問的退役軍人，韓蕭林兵長。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"기초의무교육 수료를 위해 잠시 이곳에서 신세를 지게 되었으니 당분간 잘 부탁한다.","JPN":"基礎義務教育を修了すべく、しばらくここで厄介になる予定だ。以後よろしく頼む。","ENG":"I have been assigned to this facility to complete my compulsory education. I look forward to my time spent here.","TWN":"為了完成基礎義務教育，會在這裡暫時受到大家照顧，還請大家多多指教。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"STUDENT_EXTRA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"STUDENT_EXTRA_NULL_NULL","text":{"KOREA":"저, 정말 군인인가?","JPN":"ほ、本当に軍人さんなのかな？","ENG":"I-is she a real soldier?","TWN":"妳、妳真的是軍人嗎？"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"STUDENT_EXTRA_NULL_NULL","text":{"KOREA":"에이, 그럴 리가...... 군인은 어른들이 하는 거잖아.","JPN":"んなわけねえって……軍人はみんな大人だろ？","ENG":"Nah, that can't be true... Soldier is a job for adults.","TWN":"不會吧……軍人不是大人做的事情嗎？"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"비록 이곳에 배움을 얻으러 오긴 했지만 가르침을 나누는 것도 베테랑 솔저의 의무.","JPN":"学びを求めてここに来た身ではあるが、知識を分かち合うことも\\nベテランソルジャーたる者の務めである。","ENG":"Although I have come to learn, it is the responsibility of a veteran to share the knowledge as well.","TWN":"雖然我是為了學習才來到這裡，但和大家分享知識也是退役軍人的義務。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"혹시라도 총기조립이나 파지법, 야전 전투술에 대해 궁금한 사람이 있다면 본관에게 얼마든지 물어봐도 좋다.","JPN":"もし銃器の組み立て方や\\n構え方、実戦戦闘術について知りたい者がいるならば、\\n本官がいくらでも質問に答えよう。","ENG":"If any of you are curious about firearm assembly, phage techniques, or field combat, feel free to come ask me about them.","TWN":"如果大家對組裝槍械，野戰戰法有興趣的話，請儘管來問本官。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"특히 이 몸이 개발한 근접전투 사격술인 클로즈 쿼터 슈팅 스킬은 용병 업계에서도 소문이 자자한......","JPN":"特に本官が編み出した近接戦闘射撃術、\\nクローズクォーターシューティングスキルは、傭兵業界においても\\n大変評判が……","ENG":"The close-quarter shooting skill I have developed is already well-known amongst mercenaries—","TWN":"特別是本官開發的近戰射擊術：近身四一射擊法，在傭兵界也是很有名的……"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"TEACHER_EXTRA_F_NULL","text":{"KOREA":"흠! 소림 양. 수업을 시작해야하니 그만 들어가서 자리에 앉으세요.","JPN":"おっほん！　ハネダさん、授業を始めますのでそろそろ席についてくださいね。","ENG":"Ahem! Sorim. Class is starting soon. Please go on and take a seat.","TWN":"咳咳，韓蕭林同學。我們要開始上課了，請妳先回到自己的座位上吧。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"앗! 네!","JPN":"あっ、はい！","ENG":"Oh! Yes, of course!","TWN":"啊！是！"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"subtitle","speaker":null,"text":{"KOREA":"1교시: <color=#ffd34c>수학시간</color>     ","JPN":"1時限目：<color=#ffd34c>数学</color>     ","ENG":"1st Period: <color=#ffd34c>Math</color>     ","TWN":"第1節課: <color=#ffd34c>數學課</color>"},"stage":{"bg":"BLACK","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"TEACHER_EXTRA_F_NULL","text":{"KOREA":"자, 이번 문제는 새로 온 친구가 풀어보도록 할까?","JPN":"さて、この問題は、新しいお友達に解いてもらいましょう。","ENG":"Okay, why don't we ask our new friend to solve this problem?","TWN":"那麼，這個問題就由新來的同學解一下吧？"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"TEACHER_EXTRA_F_NULL","text":{"KOREA":"120개의 군밤을 철수와 영희가 6대4로 나눠 가지려고 해요. 그럼 철수가 몇 개를 가져갈까요?","JPN":"タローくんとハナコさんが、120個の焼き栗を6対4で分けようとしています。タローくんの分はいくつになるでしょう？","ENG":"Tom and Jane is trying to split 120 chestnuts in a 6:4 ratio. How many should Tom take?","TWN":"120個的栗子由哲秀和永熙依照6比4的比例對分後，哲秀會得到多少個栗子呢？"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"그러니까...... 하나...... 두울......","JPN":"ええっと……ひとーつ……ふたーつ……","ENG":"Uh... One... Two...","TWN":"那個……一個……兩個……"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L29_1","type":"dialog","speaker":"TEACHER_EXTRA_F_NULL","text":{"KOREA":".......손가락으로 세는 것보단 수식을 사용해 보는 게 어떻겠니?","JPN":"……指で数えるより、計算で解いてみた方がいいと思うな。","ENG":"Why don't you try using an equation instead of your fingers?","TWN":"……比起用手指數，不如用一下公式吧？"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"......교, 교관! 이런 부조리한 문제는 용납할 수 없다!","JPN":"……教、教官！　このような\\n理不尽な問題、認めるわけにはいかん！","ENG":"M-Ma'am! I cannot accept this irrational problem!","TWN":"……教、教官！這種不合理的問題我無法接受！"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L31_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"보급품은 6대4가 아니라 모두에게 공평하게 나눠져야 한다!","JPN":"6対4に分けるとはいかなる了見か！　補給品はみんなで公平に分けるべきだ！","ENG":"All supplies should be shared equally, not 6:4!","TWN":"補給品不該是6比4，而是要全部平分才對！"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"subtitle","speaker":null,"text":{"KOREA":"4교시: <color=#ffd34c>체육시간</color>     ","JPN":"4時限目：<color=#ffd34c>体育</color>     ","ENG":"4th Period: <color=#ffd34c>P.E.</color>     ","TWN":"第四節課: <color=#ffd34c>體育課</color>"},"stage":{"bg":"BLACK","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"TEACHER_EXTRA_M_NULL","text":{"KOREA":"윗몸 일으키기 0개. 팔 굽혀 펴기 0개. 100미터 달리기는 중도포기......","JPN":"上体起こし0回。腕立て伏せ0回。\\n100メートル走は途中でリタイア……","ENG":"0 sit-ups. 0 push-ups. Retired from the 100m dash...","TWN":"仰臥起坐0下，伏地挺身0下，100米衝刺中途放棄……"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"TEACHER_EXTRA_M_NULL","text":{"KOREA":"아카데미에서 체력실기가 일반인 기준보다 미달인 경우는 전례가 없는데......","JPN":"アカデミーの体力実技で一般人以下の成績が\\n出るなんて、前代未聞だけど……","ENG":"I've never seen anyone from the Academy falling below civilian standards in the physical examination...","TWN":"在這個學院，體力未達到普通人水準的還真是前所未見……"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"헥... 헥... 고, 고통스럽다......","JPN":"ぜぇ……ぜぇ……き、厳しいぃ～。","ENG":"*Pant* *Pant* Th-this is painful...","TWN":"哈啊……哈啊……好、好痛苦……"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"이렇게 고통스러운 전장은...... 사하라 사막 방어전 이후 처음이다......","JPN":"ここまで厳しい戦場は……\\nサハラ砂漠での防衛戦以来だ……","ENG":"I haven't experienced a battlefield this painful... since the Sahara Desert Defense...","TWN":"這麼痛苦的戰場……自撒哈拉沙漠防衛禦戰以後還是第一次……"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"TEACHER_EXTRA_M_NULL","text":{"KOREA":"자, 다음은 뜀틀넘기다. 이번 실기가 마지막이니 조금만 더 힘내렴.","JPN":"ほら、次は跳び箱よ。今回の実技はこれで\\n最後だから、あと一頑張りだよ。","ENG":"Alright, let's try vaulting next. This is the final examination, so just try your best.","TWN":"好，下一個是跳箱。這是最後一個測試了，再努力一下。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"흐으......","JPN":"はぅぅ……","ENG":"Ugh...","TWN":"嘿啊……"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"TEACHER_EXTRA_M_NULL","text":{"KOREA":"소, 소림아. 뜀틀에 들이받기 전에 점프를 해야 한다니까!","JPN":"ハ、ハネダさん。跳び箱に体当たりして\\nどうするの。そこはジャンプしないと！","ENG":"S-Sorim. You have to jump before you run into it!","TWN":"蕭、蕭林同學，碰到跳箱前妳得跳起來才行啊！"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"흐그극......","JPN":"ふぐぐぅっ……","ENG":"Ughh...","TWN":"唔唔唔……"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"의, 의무병을 부, 탁, 한......","JPN":"え、衛生兵を、呼ん、で、くれ……","ENG":"C-call a medic...","TWN":"醫、醫護兵……"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"꼬르륵......","JPN":"グゥ～ギュルル……","ENG":"*Gurgle*","TWN":"咕嚕嚕……"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_HIT_SMALL"},{"id":"L1_1","type":"dialog","speaker":"STUDENT_EXTRA_NULL_NULL","text":{"KOREA":"앗! 선생님, 소림이 기절한 것 같아요!","JPN":"あっ、先生！　ハネダさん、気絶したみたいです！","ENG":"Ah! I think Sorim fainted!","TWN":"啊！老師，蕭林好像暈倒了！"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};